<?php
session_start();require_once '../config/base.php';
if(!isset($_SESSION['admin_id'])){header('Location: '.BASE_URL.'/login.php');exit;}
require_once '../config/db.php';
$fe=intval($_GET['event_id']??0);$fd=trim($_GET['dept']??'');$sr=trim($_GET['search']??'');
$w=['1=1'];$p=[];
if($fe>0){$w[]='r.event_id=?';$p[]=$fe;}
if($fd!==''){$w[]='u.department=?';$p[]=$fd;}
if($sr!==''){$w[]='(u.name LIKE ? OR u.email LIKE ? OR e.title LIKE ?)';$p[]="%$sr%";$p[]="%$sr%";$p[]="%$sr%";}
$ws=implode(' AND ',$w);
$s=$pdo->prepare("SELECT r.*,u.name AS uname,u.email,u.department,u.year,e.title AS etitle,e.event_date,e.category FROM registrations r JOIN users u ON r.user_id=u.id JOIN events e ON r.event_id=e.id WHERE $ws ORDER BY r.registered_at DESC");$s->execute($p);$regs=$s->fetchAll();
$aevs=$pdo->query("SELECT id,title FROM events ORDER BY event_date DESC")->fetchAll();
$adepts=$pdo->query("SELECT DISTINCT department FROM users ORDER BY department")->fetchAll();
?>
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/><title>Registrations — CampusVerse</title>
<link href="https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=DM+Sans:wght@400;500&display=swap" rel="stylesheet"/>
<style>:root{--bg:#050810;--surface:#0d1117;--card:#111827;--border:rgba(255,255,255,0.08);--accent:#6EE7B7;--accent2:#818CF8;--accent3:#F472B6;--text:#F1F5F9;--muted:#94A3B8;--error:#F87171;}*{box-sizing:border-box;margin:0;padding:0;}body{background:var(--bg);color:var(--text);font-family:'DM Sans',sans-serif;min-height:100vh;}.layout{display:flex;min-height:100vh;}.sidebar{width:250px;background:var(--surface);border-right:1px solid var(--border);padding:2rem 1.5rem;position:fixed;height:100vh;display:flex;flex-direction:column;}.main{margin-left:250px;padding:2.5rem;flex:1;}.slogo{font-family:'Syne',sans-serif;font-weight:800;font-size:1.4rem;background:linear-gradient(135deg,var(--accent),var(--accent2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin-bottom:.4rem;display:block;}.abadge{background:rgba(244,114,182,.1);border:1px solid rgba(244,114,182,.2);color:var(--accent3);font-size:.68rem;font-weight:700;text-transform:uppercase;padding:.2rem .6rem;border-radius:100px;display:inline-block;margin-bottom:2rem;}.ni{display:flex;align-items:center;gap:.75rem;padding:.65rem 1rem;border-radius:10px;text-decoration:none;color:var(--muted);font-size:.875rem;margin-bottom:2px;transition:all .2s;}.ni:hover,.ni.active{background:rgba(110,231,183,.08);color:var(--accent);}.sf{margin-top:auto;padding-top:1.5rem;border-top:1px solid var(--border);}.btn-lo{display:block;padding:.6rem;text-align:center;border-radius:8px;border:1px solid var(--border);color:var(--muted);text-decoration:none;font-size:.82rem;transition:all .2s;}.btn-lo:hover{border-color:var(--error);color:var(--error);}.ph{margin-bottom:2rem;}.ph h1{font-family:'Syne',sans-serif;font-size:1.8rem;font-weight:800;}.ph p{color:var(--muted);margin-top:.25rem;}.sr{display:flex;gap:.75rem;flex-wrap:wrap;margin-bottom:1.5rem;}.fi{padding:.6rem 1rem;background:var(--card);border:1px solid var(--border);border-radius:10px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:.875rem;outline:none;transition:all .2s;}.fi:focus{border-color:var(--accent);}select.fi option{background:var(--card);}.btn-f{padding:.6rem 1.4rem;background:linear-gradient(135deg,var(--accent),var(--accent2));border:none;border-radius:10px;color:#050810;font-weight:700;cursor:pointer;font-size:.875rem;font-family:'DM Sans',sans-serif;}.btn-c{padding:.6rem 1rem;background:rgba(255,255,255,.04);border:1px solid var(--border);border-radius:10px;color:var(--muted);cursor:pointer;font-size:.875rem;text-decoration:none;display:inline-block;}.ms{display:flex;gap:1rem;margin-bottom:1.5rem;flex-wrap:wrap;}.mc{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1rem 1.5rem;display:flex;align-items:center;gap:.75rem;}.mv{font-family:'Syne',sans-serif;font-size:1.5rem;font-weight:800;color:var(--accent);}.ml{color:var(--muted);font-size:.8rem;}.tw{background:var(--card);border:1px solid var(--border);border-radius:16px;overflow:hidden;}table{width:100%;border-collapse:collapse;}th{padding:.875rem 1.25rem;text-align:left;font-size:.72rem;font-weight:600;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;border-bottom:1px solid var(--border);background:rgba(255,255,255,.02);}td{padding:.875rem 1.25rem;border-bottom:1px solid rgba(255,255,255,.04);font-size:.875rem;}tr:last-child td{border:none;}tr:hover td{background:rgba(255,255,255,.02);}.tag{display:inline-block;padding:.2rem .6rem;border-radius:100px;font-size:.7rem;font-weight:600;}.tconf{background:rgba(110,231,183,.1);color:var(--accent);}.tb{background:rgba(129,140,248,.1);color:var(--accent2);}.empty{text-align:center;padding:4rem;color:var(--muted);}@media(max-width:768px){.sidebar{display:none;}.main{margin-left:0;}}</style></head><body>
<div class="layout">
<aside class="sidebar"><span class="slogo">CampusVerse</span><span class="abadge">Admin Panel</span><a href="<?=BASE_URL?>/admin/admin_dashboard.php" class="ni">📊 Dashboard</a><a href="<?=BASE_URL?>/admin/manage_events.php" class="ni">📅 Manage Events</a><a href="<?=BASE_URL?>/admin/add_event.php" class="ni">➕ Add Event</a><a href="<?=BASE_URL?>/admin/view_registrations.php" class="ni active">👥 Registrations</a><div class="sf"><a href="<?=BASE_URL?>/logout.php" class="btn-lo">Sign Out</a></div></aside>
<main class="main">
  <div class="ph"><h1>Registrations</h1><p>All student event registrations.</p></div>
  <div class="ms">
    <div class="mc"><div><div class="mv"><?=count($regs)?></div><div class="ml">Results</div></div></div>
    <div class="mc"><div><div class="mv" style="color:var(--accent2)"><?=$pdo->query("SELECT COUNT(*) FROM registrations WHERE status='confirmed'")->fetchColumn()?></div><div class="ml">Total Confirmed</div></div></div>
    <div class="mc"><div><div class="mv" style="color:var(--accent3)"><?=$pdo->query("SELECT COUNT(DISTINCT user_id) FROM registrations")->fetchColumn()?></div><div class="ml">Unique Students</div></div></div>
  </div>
  <form method="GET"><div class="sr">
    <input type="text" name="search" class="fi" placeholder="🔍 Search..." value="<?=htmlspecialchars($sr)?>" style="min-width:240px"/>
    <select name="event_id" class="fi"><option value="">All Events</option><?php foreach($aevs as $ev):?><option value="<?=$ev['id']?>" <?=$fe==$ev['id']?'selected':''?>><?=htmlspecialchars(substr($ev['title'],0,40))?></option><?php endforeach;?></select>
    <select name="dept" class="fi"><option value="">All Departments</option><?php foreach($adepts as $d):?><option value="<?=htmlspecialchars($d['department'])?>" <?=$fd===$d['department']?'selected':''?>><?=htmlspecialchars($d['department'])?></option><?php endforeach;?></select>
    <button type="submit" class="btn-f">Filter</button><a href="<?=BASE_URL?>/admin/view_registrations.php" class="btn-c">Clear</a>
  </div></form>
  <div class="tw"><?php if(empty($regs)):?><div class="empty"><div style="font-size:3rem;margin-bottom:1rem">📭</div><p>No registrations found.</p></div>
  <?php else:?><table><thead><tr><th>#</th><th>Student</th><th>Dept</th><th>Yr</th><th>Event</th><th>Category</th><th>Event Date</th><th>Registered</th><th>Status</th></tr></thead><tbody>
  <?php foreach($regs as $i=>$r):?><tr><td style="color:var(--muted)"><?=$i+1?></td><td><div style="font-weight:600"><?=htmlspecialchars($r['uname'])?></div><div style="font-size:.72rem;color:var(--muted)"><?=htmlspecialchars($r['email'])?></div></td><td style="color:var(--muted);font-size:.82rem"><?=htmlspecialchars($r['department'])?></td><td style="text-align:center"><span class="tag" style="background:rgba(255,255,255,.05);color:var(--muted)">Y<?=$r['year']?></span></td><td style="max-width:160px;font-weight:500"><?=htmlspecialchars(substr($r['etitle'],0,30))?><?=strlen($r['etitle'])>30?'…':''?></td><td><span class="tag tb"><?=htmlspecialchars($r['category'])?></span></td><td style="color:var(--muted);font-size:.82rem"><?=date('M j, Y',strtotime($r['event_date']))?></td><td style="color:var(--muted);font-size:.82rem"><?=date('M j, Y',strtotime($r['registered_at']))?></td><td><span class="tag tconf"><?=ucfirst($r['status'])?></span></td></tr><?php endforeach;?></tbody></table><?php endif;?>
  </div>
</main></div></body></html>